              <Save size={18} /> Lưu sản phẩm
            </button>
          </div>
        </div>

        <div className="max-w-6xl mx-auto p-6 grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* ... (Existing Form Layout - Condensed for brevity, functionality maintained) ... */}
